import{_ as a,c as o,o as i,a8 as l}from"./chunks/framework.BrmF0WDH.js";const u=JSON.parse('{"title":"新人上手阅读地图","description":"","frontmatter":{},"headers":[],"relativePath":"onboarding/index.md","filePath":"onboarding/index.md","lastUpdated":1777649372000}'),d={name:"onboarding/index.md"};function r(t,e,c,n,h,p){return i(),o("div",null,e[0]||(e[0]=[l('<h1 id="新人上手阅读地图" tabindex="1">新人上手阅读地图 <a class="header-anchor" href="#新人上手阅读地图" aria-label="Permalink to &quot;新人上手阅读地图&quot;">​</a></h1><p>这组文档不是 API 罗列，而是按“新人理解项目”的顺序重建一遍工程认知。</p><p>如果你刚接手这个仓库，建议按下面顺序读：</p><ol><li><a href="./00-新人30分钟了解项目精髓/">00-新人30分钟了解项目精髓</a></li><li><a href="./01-总览/">01-总览</a></li><li><a href="./02-Schema与核心数据模型/">02-Schema与核心数据模型</a></li><li><a href="./03-Editor编辑器状态流/">03-Editor编辑器状态流</a></li><li><a href="./04-Sandbox画布与交互/">04-Sandbox画布与交互</a></li><li><a href="./05-DataSource数据驱动/">05-DataSource数据驱动</a></li><li><a href="./06-Runtime渲染与组件机制/">06-Runtime渲染与组件机制</a></li><li><a href="./07-扩展点与新人落地建议/">07-扩展点与新人落地建议</a></li></ol><h2 id="这套文档重点回答什么" tabindex="1">这套文档重点回答什么 <a class="header-anchor" href="#这套文档重点回答什么" aria-label="Permalink to &quot;这套文档重点回答什么&quot;">​</a></h2><ul><li>这个项目真正的单一事实来源是什么</li><li>编辑器、画布、运行时到底谁负责什么</li><li>数据源变化后，页面为什么会重新渲染</li><li>为什么项目要把编辑器和运行时拆开</li><li>新人第一次改需求，应该从哪里下手才不会绕远路</li></ul><h2 id="先给结论" tabindex="1">先给结论 <a class="header-anchor" href="#先给结论" aria-label="Permalink to &quot;先给结论&quot;">​</a></h2><p>Quantum Lowcode 的核心不是“拖拽”，而是“Schema 驱动的可执行页面系统”。</p><p>项目把一个低代码页面拆成了 4 层职责：</p><ul><li><code>Schema</code> 负责描述页面结构、组件属性、事件和数据源</li><li><code>Core</code> 负责把静态 Schema 变成带生命周期、事件、依赖追踪能力的节点树</li><li><code>Editor + Sandbox</code> 负责编辑时的可视化交互，不负责真正业务渲染</li><li><code>Runtime + UI</code> 负责把当前页面渲染出来，并在运行时响应数据和事件</li></ul><p>这也是你理解整个仓库时最重要的主线。</p><h2 id="推荐阅读方式" tabindex="1">推荐阅读方式 <a class="header-anchor" href="#推荐阅读方式" aria-label="Permalink to &quot;推荐阅读方式&quot;">​</a></h2><p>如果你只有 30 分钟，先读 <code>00</code> 和 <code>01</code>。</p><p>如果你要开始改需求，至少补读 <code>03</code>、<code>04</code>、<code>05</code>。</p><p>如果你要新增组件、扩展运行时、接入业务能力，再读 <code>06</code> 和 <code>07</code>。</p>',15)]))}const m=a(d,[["render",r]]);export{u as __pageData,m as default};
